package com.museumheist.game.input;import android.graphics.PointF;public class VirtualJoystick{private final PointF base=new PointF(),knob=new PointF();private final float deadZone;private int pointerId=-1;private float maxDistance,inputX,inputY;public VirtualJoystick(float maxDistance,float deadZone){this.maxDistance=maxDistance;this.deadZone=deadZone;}public void setMaxDistance(float v){maxDistance=Math.max(v,1);}public void setDefaultPosition(float x,float y){if(!isActive()){base.set(x,y);knob.set(base);}}public boolean onPointerDown(int id,float x,float y){if(pointerId!=-1)return false;pointerId=id;base.set(x,y);knob.set(base);inputX=inputY=0;return true;}public boolean onPointerMove(int id,float x,float y){if(pointerId==-1||id!=pointerId)return false;float dx=x-base.x,dy=y-base.y,d=(float)Math.hypot(dx,dy);if(d>maxDistance&&d>0){dx=dx/d*maxDistance;dy=dy/d*maxDistance;d=maxDistance;}knob.set(base.x+dx,base.y+dy);float n=d/maxDistance;if(n<deadZone||d<=0){inputX=inputY=0;}else{float a=(n-deadZone)/(1-deadZone);inputX=dx/d*a;inputY=dy/d*a;}return true;}public boolean onPointerUp(int id){if(pointerId!=id)return false;reset();return true;}public float getInputX(){return inputX;}public float getInputY(){return inputY;}public PointF getBase(){return base;}public PointF getKnob(){return knob;}public float getMaxDistance(){return maxDistance;}public boolean isActive(){return pointerId!=-1;}public void reset(){pointerId=-1;inputX=inputY=0;knob.set(base);}}
